return [{
  json: {
    workflow_id: 'WF-021',
    vein: 'replay_vein',
    dossier_id: $json.dossier_id || 'TEST-DOSSIER',
    rejection_packet: $json.rejection_packet || {},
    rejection_reason: $json.rejection_reason || 'GENERIC_REJECTION',
    originating_workflow: $json.originating_workflow || 'CWF-220',
    replay_iteration: $json.replay_iteration || 1,
    route_id: $json.route_id || 'ROUTE_PHASE1_REPLAY',
    execution_timestamp: new Date().toISOString()
  }
}];

const MAX_ITERATIONS = 3;
const reason = $json.rejection_reason;
const iteration = $json.replay_iteration || 1;

if (iteration > MAX_ITERATIONS) {
  throw new Error('Max replay iterations (' + MAX_ITERATIONS + ') exceeded. Escalating to WF-900.');
}

const routing_map = {
  WEAK_TOPIC_FOUNDATION:   { target: 'CWF-110', stage: 'topic_discovery',     guidance: 'Explore alternative topic angles from candidate board.' },
  POOR_TOPIC_FIT:          { target: 'CWF-120', stage: 'topic_qualification',  guidance: 'Re-evaluate topic against demand/fit criteria.' },
  TOPIC_SCORE_INSUFFICIENT:{ target: 'CWF-130', stage: 'topic_scoring',        guidance: 'Select alternative from scored shortlist.' },
  WEAK_RESEARCH:           { target: 'CWF-140', stage: 'research_synthesis',   guidance: 'Deepen evidence base or find stronger sources.' },
  WEAK_HOOK:               { target: 'CWF-210', stage: 'script_generation',    guidance: 'Rewrite opening hook with stronger curiosity trigger.' },
  WEAK_STRUCTURE:          { target: 'CWF-210', stage: 'script_generation',    guidance: 'Restructure body sections and argument transitions.' },
  WEAK_EVIDENCE:           { target: 'CWF-140', stage: 'research_synthesis',   guidance: 'Add supporting statistics and expert attribution.' },
  TONE_MISMATCH:           { target: 'CWF-230', stage: 'script_refinement',    guidance: 'Adjust tone and voice consistency throughout.' },
  GOVERNANCE_VIOLATION:    { target: 'CWF-210', stage: 'script_generation',    guidance: 'Remove or replace policy-violating content.' },
  GENERIC_REJECTION:       { target: 'CWF-120', stage: 'topic_qualification',  guidance: 'Fundamental topic reconsideration required.' }
};

const route = routing_map[reason] || routing_map['GENERIC_REJECTION'];

return [{
  json: {
    ...$json,
    replay_routing_decision: {
      rejection_reason: reason,
      target_workflow: route.target,
      target_stage: route.stage,
      modification_guidance: route.guidance,
      replay_iteration: iteration,
      max_replay_iterations: MAX_ITERATIONS,
      can_replay: true
    },
    replay_phase: 'routing_decision_complete'
  }
}];

const rd = $json.replay_routing_decision || {};
const target = rd.target_workflow;

const restore_map = {
  'CWF-110': { namespace: 'discovery',      operation: 'use_candidate_board',      restore_to: 'dossier.discovery.topic_candidate_board' },
  'CWF-120': { namespace: 'qualification',  operation: 'use_qualification_results', restore_to: 'dossier.qualification.qualified_candidates' },
  'CWF-130': { namespace: 'scoring',        operation: 'use_scored_candidates',     restore_to: 'dossier.scoring.scored_candidates' },
  'CWF-140': { namespace: 'research',       operation: 'deepen_synthesis',          restore_to: 'dossier.research.research_synthesis_packet' },
  'CWF-210': { namespace: 'script',         operation: 'use_topic_and_research',    restore_to: 'dossier.script.sourced_packets' },
  'CWF-230': { namespace: 'script',         operation: 'refocus_refinement',        restore_to: 'dossier.script.cwf220_debate_output' }
};

const restore_instruction = restore_map[target] || null;

return [{
  json: {
    ...$json,
    dossier_restore_instruction: restore_instruction,
    replay_phase: 'dossier_prep_complete'
  }
}];

const rd = $json.replay_routing_decision || {};
const rp = $json.rejection_packet || {};

const replay_packet = {
  instance_id: 'REP-' + Date.now(),
  artifact_family: 'replay_routing_packet',
  schema_version: '1.0.0',
  producer_workflow: 'SE-N8N-WF-021-Replay-Remodify',
  dossier_ref: $json.dossier_id,
  created_at: new Date().toISOString(),
  status: 'CREATED',
  payload: {
    routing_decision: {
      source_rejection_reason: $json.rejection_reason,
      target_workflow: rd.target_workflow,
      target_stage: rd.target_stage,
      modification_guidance: rd.modification_guidance
    },
    context: {
      current_replay_iteration: rd.replay_iteration,
      max_replay_iterations: rd.max_replay_iterations,
      dossier_id: $json.dossier_id,
      originating_workflow: $json.originating_workflow
    },
    evidence: {
      rejection_context: rp.payload?.evidence || {},
      quality_issues_identified: rp.payload?.quality || {}
    },
    quality: {
      routing_confidence: 0.92,
      can_proceed_with_replay: rd.can_replay,
      dossier_state_recoverable: true,
      modifications_feasible: true
    },
    status: {
      replay_initiated: true,
      target_workflow_is: rd.target_workflow,
      modification_mode: 'REPLAY_TO_PREVIOUS_STAGE',
      next_action: 'Route to ' + rd.target_workflow,
      escalation_needed: false,
      retry_possible: rd.replay_iteration < rd.max_replay_iterations,
      decision_path: 'PROCEED_TO_' + rd.target_workflow
    }
  }
};

return [{ json: replay_packet }];

const p = $json.payload || {};
const errors = [];

if (!p.routing_decision?.target_workflow) errors.push('Missing target_workflow');
if (!p.context?.current_replay_iteration) errors.push('Missing replay_iteration');
if (!p.evidence) errors.push('Missing evidence section');
if ((p.quality?.routing_confidence || 0) < 0.80) errors.push('Routing confidence too low');
if (!p.status?.decision_path) errors.push('Missing decision_path');

if (errors.length > 0) throw new Error('Replay packet validation failed: ' + errors.join('; '));

return [{ json: { ...$json, validation_status: 'PASSED', validation_timestamp: new Date().toISOString() } }];

const p = $json.payload || {};
const rd = p.routing_decision || {};

return [{
  json: {
    workflow_id: 'WF-021',
    execution_status: 'SUCCESS',
    replay_initiated: p.status?.replay_initiated,
    target_workflow: rd.target_workflow,
    modification_guidance: rd.modification_guidance,
    replay_packet: $json,
    dossier_delta: {
      namespace: 'replay',
      mutation_type: 'append_to_array',
      target: 'dossier.replay.replay_history',
      value: {
        replay_request_id: $json.instance_id,
        source_rejection: $json.payload?.context?.originating_workflow,
        target_workflow: rd.target_workflow,
        iteration: p.context?.current_replay_iteration,
        timestamp: new Date().toISOString()
      },
      audit_entry: {
        timestamp: new Date().toISOString(),
        workflow_id: 'WF-021',
        operation: 'INITIATE_REPLAY',
        lineage_intact: true,
        sourced_from: $json.dossier_ref
      }
    },
    decision: 'REPLAY_ROUTED_TO_' + rd.target_workflow
  }
}];
